var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"RITA_HORIZON_NULL_ON","text":{"KOREA":"하아...... 하아......","JPN":"はあ……はあ……","ENG":"*Huff...* *Huff...*","TWN":"呼呼……呼呼……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_ON","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RITA_HORIZON_NULL_ON","text":{"KOREA":"침식파가 너무 강해서인가......? 평소보다 빨리 지쳐 버렸군.","JPN":"侵食波が強すぎるせいか……？　普段より疲れが早く来るな。","ENG":"Maybe the Corruption Ray was too potent this time... I got worn out sooner than usual.","TWN":"是侵蝕波太強了嗎……？這麼快就累了。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"쓰러뜨렸어......! 3종 침식체를!","JPN":"倒した……！　第3種侵食体を！","ENG":"She defeated it! A Category 3!","TWN":"擊殺了……！3類侵蝕體！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"리타 언니, 멋졌어요!","JPN":"リタお姉ちゃん、カッコイイ！","ENG":"That was incredible, Rita!","TWN":"麗塔姐姐，真是太棒了！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"RITA_HORIZON_NULL_ON","text":{"KOREA":"......빈 말은 됐어. 호라이즌이나 어서 찾아.","JPN":"……思ってもないこと言うな。さっさとホライズンを探せ。","ENG":"Nobody likes a brown-noser, kid. Just go find Horizon.","TWN":"……別說這些了，快去找地平線。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"구조 신호가 접수된 모양이니까.","JPN":"救助信号が届いたようだからな。","ENG":"I think someone's picked up our May Day signal.","TWN":"求救信號好像被接收了。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TELE_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>여기는 데이마인 채굴 1팀. 구조 요청을 받고 지원 왔습니다.</color>","JPN":"<color=#ffd34c>こちらはデイマイン採掘1チーム。救助要請を受けて参りました。</color>","ENG":"<color=#ffd34c>This is Daymine Mining Team 1. We're here in response to a May Day call.</color>","TWN":"<color=#ffd34c>這裡是戴瑪因第1採礦隊。我們收到求救信號前來支援。</color>"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L17_1","type":"dialog","speaker":"TELE_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>관리국 소속 정기 순찰 함선 툴루즈입니다. 지금 곧 의료반을 강하시키겠습니다.</color>","JPN":"<color=#ffd34c>管理局所属の定期巡察艦船トゥールーズです。今すぐ医療班を降下させます。</color>","ENG":"<color=#ffd34c>This is Administration patrol ship Toulouse. We're sending medics your way right now.</color>","TWN":"<color=#ffd34c>這裡是管理局所屬的定期巡邏艦船圖盧茲，現在馬上降落醫療班。</color>"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PMC_NPC_TYPEA_NULL","text":{"KOREA":"이야호오!!","JPN":"やった！！","ENG":"Hooray!","TWN":"呀吼！！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"조금 늦었어! 멋진 장면을 볼 기회였는데!","JPN":"遅れて来たな！　すごい場面を見るチャンスだったのに！","ENG":"You guys came a bit too late! You missed a great show!","TWN":"來晚了一步！錯過了精彩場面！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"우와, 정규 태스크포스들이 쓰는 함선들은 어마어마하네요......","JPN":"うわあ、正規タスクフォースカンパニーが使う艦船はとんでもない大きさですね……","ENG":"Wow... These official TASKFORCEs sure have huge ships...","TWN":"嗚哇，正規特遣勢力使用的艦船真是不同凡響啊……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그래. 뒷일은 이제 저 녀석들에게 맡기면 되겠지.","JPN":"そうだな。後は奴らに任せとけばいいだろ。","ENG":"Yeah. Looks like we can leave the cleanup to those guys.","TWN":"是啊。後面的事交給他們就好了。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"힘을 너무 쓴 건 아쉽군. 이터니움 한 조각으론 기별도 안 갈 텐데.","JPN":"力を使い過ぎたのは残念だ。エタニウム一欠片じゃ足りないか。","ENG":"Too bad I overexerted myself. It'll take more than a single shard of Eternium to charge me back up.","TWN":"耗費太多力氣了。一塊永恆之金還不夠塞牙縫呢。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그렇지. 돌아가는 길에도 멀미는 날 테니 미리 각오해 둬.","JPN":"ああそうだ。帰り道も酔うはずだから覚悟しておけ。","ENG":"Oh, yeah. You'll get motion sickness on the way back as well. Brace yourself.","TWN":"對了。回去的路上也會暈船吧，先做好準備。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"우으...... 멀미 때문에라도 두 번 다시는 안 올래요......","JPN":"うぅ……ダイブ酔いなんて二度とご免だし、もう来ないことにします……","ENG":"Ugh... I'm never coming back here again. Especially because of the motion sickness...","TWN":"嗚哇……暈船滋味我不想再體會第二次了……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>......가 되어라.</color>","JPN":"<color=#ff3636>……になれ。</color>","ENG":"<color=#ff3636>... our sister.</color>","TWN":"<color=#ff3636>……成為。</color>"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"꼬맹이, 방금 그 소리 들었어?","JPN":"ガキ、今の声を聞いたか？","ENG":"Did you hear that, kid?","TWN":"小鬼，你聽到聲音了嗎？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"넹? 어떤 소리요?","JPN":"え？　誰の声ですか？","ENG":"Huh? Hear what?","TWN":"嗯？什麼聲音？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"아 참! 넋 놓고 있을 때가 아니에요! 어서 부상자 분들도 옮겨야죠!","JPN":"そうだ！　のんびり休んでる場合じゃありません！　負傷者の方を運ばないと！","ENG":"Oh, right! We shouldn't just lounge around like this! We have to help them move the wounded!","TWN":"啊，對了！現在不是發呆的時候！要趕快轉移傷患！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"아냐. 방금 분명히 들렸어.","JPN":"いや、確かに聞こえた。","ENG":"No... I could swear I heard something.","TWN":"不，剛剛明明聽到了。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"수정을 발견했을 때 들었던...... 그 기분 나쁜 목소리가.","JPN":"水晶を見つけた時に聞こえた……あの気味の悪い声が。","ENG":"The creepy voice... that I heard when we found the crystal.","TWN":"發現水晶時聽到的……那個讓人不舒服的聲音。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>시련 끝에, 우리의 자매가 되어라.</color>","JPN":"<color=#ff3636>試練の末、我々の姉妹になるのだ。</color>","ENG":"<color=#ff3636>Upon the tribulation, ye shall become our sister.</color>","TWN":"<color=#ff3636>考驗過後，你就會成為我們的姐妹。</color>"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"TELE_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>조난자들 신원 검사 준비해. 스캐빈저들이 파놓은 함정일 수도 있다.</color>","JPN":"<color=#ffd34c>遭難者の身元検査の準備をしろ。スカベンジャーに仕組まれた罠かもしれない。</color>","ENG":"<color=#ffd34c>Prepare to ID everyone down there. It could be a trap set by the Scavengers.</color>","TWN":"<color=#ffd34c>準備檢查遇難者的身份。這可能是清道夫們設下的陷阱。</color>"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"TELE_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>응? 고준위 침식파 반응이라고? 그게 무슨 소리야?</color>","JPN":"<color=#ffd34c>は？　高レベル侵食波反応だと？　どういうことだ？</color>","ENG":"<color=#ffd34c>Huh? The Corruption Ray response is spiking? What are you talking about?</color>","TWN":"<color=#ffd34c>嗯？高階侵蝕波？那是什麼意思？</color>"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"TELE_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>3종 침식체가...... 셋이나?!</color>","JPN":"<color=#ffd34c>第3種侵食体が……3体も！？</color>","ENG":"<color=#ffd34c>What do you mean there are... THREE Category 3's?!</color>","TWN":"<color=#ffd34c>3類侵蝕體……有三個？！</color>"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_46"},{"id":"L50_1","type":"dialog","speaker":"TELE_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>여기는 툴루즈! 구조 활동 중 3종 침식체 다수와 조우! 반복한다! 여기는 툴루즈!</color>","JPN":"<color=#ffd34c>こちらはトゥールーズ！　救助活動中に第3種侵食体複数と遭遇！　繰り返す！　こちらはトゥールーズ！</color>","ENG":"<color=#ffd34c>This is the Toulouse! We've encountered multiple Category 3 C.O.s during the rescue! I repeat! This is the Toulouse!</color>","TWN":"<color=#ffd34c>這裡是圖盧茲！救援活動中遭遇多個3類侵蝕體！重複！這裡是圖盧茲！</color>"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"TELE_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>적들로부터 고에너지 가속 현상 발생! 회피 불가합니다!</color>","JPN":"<color=#ffd34c>敵から高エネルギー加速現象が発生！　回避できません！</color>","ENG":"<color=#ffd34c>High energy blast detected from the C.O.s! We can't evade it!</color>","TWN":"<color=#ffd34c>發現敵人有高能量加速現象！無法閃避！</color>"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"언니! 저쪽에 다른 침식체가......!","JPN":"リタお姉ちゃん！　あっちに他の侵食体が……！","ENG":"Rita! There's another C.O. over there!","TWN":"姐姐！那邊有其他侵蝕體……！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"가지 마, 꼬맹이! 내 뒤로 숨어!","JPN":"近付くな、ガキ！　私の後ろに隠れろ！","ENG":"Stay put, kid! Get behind me!","TWN":"別過去，小鬼！躲在我後面！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"아으으......","JPN":"ううぅ……","ENG":"Ugh...","TWN":"啊嗚嗚……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"어떻게 된 거지......? ","JPN":"どうなってるの……？ ","ENG":"What happened? ","TWN":"怎麼回事……？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"리타 언니가 감싸 준 다음에...... 눈앞이 반짝했는데......","JPN":"リタお姉ちゃんがかばってくれて……一瞬目の前が光った気がする……","ENG":"After Rita threw herself over me... I saw something flash...","TWN":"麗塔姐姐護住我之後……眼前一閃……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"내 팔......! 누가 내 팔 좀 찾아 줘!","JPN":"俺の腕……！　誰か俺の腕を探してくれー！","ENG":"My arm! Someone please find my arm!","TWN":"我的手臂……！誰來幫我找找我的手臂！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"싫어! 이제 집으로 좀 보내 줘요! 엄마! 엄마아아아아!","JPN":"いやだ！　もう家に帰らせてくれ！　母さん！　神様……！","ENG":"No! I want to go home! Mommy! Mommeeee!","TWN":"不要啊！快放我回家！媽媽！媽媽！！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_BOOM_REPEAT"},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"힉......! 모두 다......! 히힉......! 죽을 거야......! 죽을 거라고......!","JPN":"ひっ……！　全員……！　ひいっ…！　ここで死ぬぞ……！　死んじまうんだ……！","ENG":"Hee! We're all... Hee hee! Going to die! We're all going to die!","TWN":"呃……！所有人……！呃呃……！都要死……！都去死……！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_HOWLING_03"},{"id":"L20_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"치, 침식체가......? 이렇게 많이......?","JPN":"し、侵食体が……？　こんなに大勢……？","ENG":"C-C.O.s? Where did they all come from?","TWN":"侵、侵蝕體……？怎麼這麼多……？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"리타 언니! 어디 있어요!?","JPN":"リタお姉ちゃん！　どこにいるんですか？","ENG":"Rita! Where are you?!","TWN":"麗塔姐姐！妳在哪裡！？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"큭...... 쿨럭......!","JPN":"くっ……ゲホッ……！","ENG":"Ngh... *Cough!*","TWN":"呃……咳咳……！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L26_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"언니! 일어나요, 언니!!","JPN":"リタお姉ちゃん！　起きてください！！","ENG":"Rita! Wake up!","TWN":"姐姐！快起來，姐姐！！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"크게 다치진 않았으니까...... 호들갑 떨지 마.","JPN":"大怪我じゃない……そんな騒ぐなよ。","ENG":"It's only a scratch... It’s no big deal.","TWN":"傷得沒有很重……別這樣大呼小叫的。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"거짓말! 움직이지도 못하면서......!","JPN":"嘘だ！　動けないくせに……！","ENG":"Liar! You can barely move!","TWN":"你騙人！你都不能動了……！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"절 감싸 주느라 그랬던 거잖아요! 제가 부축해 줄게요!","JPN":"私をかばったせいでこんな傷を……！　さあ、支えます！","ENG":"You got hurt trying to protect me! Let me help you walk!","TWN":"你都是為了保護我！我來扶你！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"그런데 이제 어떡해요? 사람들이 전부 죽어 나가는데......!","JPN":"でもどうすればいいんですか？　みんな死んでいく……！","ENG":"So what now? Everyone's dying...","TWN":"現在怎麼辦？人都死光了……！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"수송선으로 가야 돼...... 남은 방법은...... 이제 그것뿐이야......","JPN":"輸送船に向かうしかない……生き残る方法は……それだけ……","ENG":"We have to get to the ship... That's... our only chance now...","TWN":"要去運輸船那裡……剩下的方法……只有那個了……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"수송선이 이륙하려고 해요! 빨리 가야 돼요, 언니!","JPN":"輸送船が離陸します！　急がないと！","ENG":"The ship's about to take off! We have to hurry, Rita!","TWN":"運輸船要起飛了！姐姐，我們要快點走！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L35_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"멍청아......! 너 혼자 가면 되잖아......!","JPN":"バカ……！　一人で行け……！","ENG":"You fool... Just go by yourself!","TWN":"傻瓜……！你自己走不就行了……！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"전...... 그렇게 치사한 짓은 못 해요!","JPN":"私に……そんなことはできません！","ENG":"But... I could never be so selfish!","TWN":"我……不能做這種卑鄙的事！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"아니, 하기 싫어요!","JPN":"いや、したくないです！","ENG":"I don't want to!","TWN":"不，我不會那樣做的！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"조금만 참아요, 언니! 꼭 같이 우리 집으로 돌아가요!","JPN":"少しだけ我慢してください！　一緒に家に帰りましょう！","ENG":"Hang in there, Rita! Let's get home together!","TWN":"忍一下，姐姐！我們一定會一起回家的！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"뭘 뜸들이는 겁니까! 어서 현실세계로 부상하지 않고!","JPN":"何を待っているんですか！　はやく現実世界に浮上しないと！","ENG":"What are you waiting for?! Surface back to the Normalside. Now!","TWN":"還在拖拖拉拉做什麼！還不快點躍出回到現實世界！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"PMC_NPC_TYPEA_NULL","text":{"KOREA":"공간을 도약하려면 이터니움 드라이브를 예열시켜야 돼요! 잠깐이면 됩니다!","JPN":"空間跳躍をするにはエタニウムドライブを予熱しなければなりません！　少しだけ待ってください！","ENG":"We need to pre-heat the Eternium drive if we want to make a jump! It'll just take a minute!","TWN":"想要跳躍空間，就必須預熱永恆之金引擎！等一會就好！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L46_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"잠깐?! 잠깐이라고!","JPN":"はあ！？　待つ？","ENG":"A minute?! A minute you say?!","TWN":"等一會？！你說等一會！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"방금 함선 두 척이 폭발하는 거 못 봤어?! 저 괴물들한테 걸리면 우리 모두 끝장이라고!","JPN":"さっき艦船2隻が爆発したのを見てないのか！？　あの怪物たちがこっちに来たら全員おしまいだ！","ENG":"Didn't you just see two other ships explode?! We'll be done for if those monsters get us!","TWN":"你沒看到剛剛兩艘艦船怎麼爆炸的嗎？！如果被那些怪物發現，我們就全完蛋了！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"응? 지금 이 소리는......?","JPN":"ん？　今の声は……？","ENG":"Huh? What was that sound?","TWN":"嗯？這個聲音是……？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":null,"text":{"KOREA":"여기 와서 좀 도와 주세요! 사채업자랑 그 꼬마 여자애예요!","JPN":"手を貸してください！　あの闇金業者と女の子です！","ENG":"Give us a hand over here! It's the loan shark lady and the kid!","TWN":"快來幫幫忙！是放高利貸的和那個小女孩！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"하아...... 하아......","JPN":"はあ……はあ……","ENG":"*Huff...* *Huff...*","TWN":"哈啊……哈啊……"},"stage":{"bg":"SS_SHADOW_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"가, 간신히 따라잡았다......!","JPN":"や、やっと近付いた……！","ENG":"B-barely made it...","TWN":"抓、抓住了……！"},"stage":{"bg":"SS_SHADOW_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"꼬마야! 잠깐만 참아! 금방 끌어올려 줄게!","JPN":"お嬢ちゃん！　少しだけ耐えろ！　今すぐ引き上げてやる！","ENG":"Hey kid! Hang in there! We'll pull you up right away!","TWN":"孩子！你堅持一下！我馬上拉你上來！"},"stage":{"bg":"SS_SHADOW_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"기다려요!","JPN":"待ってください！","ENG":"Wait!","TWN":"等等！"},"stage":{"bg":"SS_SHADOW_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"저기 보세요! 3종 침식체들이 이제 우릴 노리고 있습니다!","JPN":"あそこを！　第3種侵食体がこっちを狙ってきます！","ENG":"Look! The Category 3's are coming after us next!","TWN":"看那邊！3類侵蝕體正在盯著我們呢！"},"stage":{"bg":"SS_SHADOW_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"지, 진짜다! 방금 전까지는 가만히 있었는데?!","JPN":"ほ、本当だ！　さっきまでは反応していなかったのに！","ENG":"I-it's true! But they weren't moving just till now!","TWN":"真、真的！剛剛不是還老老實實的嗎？！"},"stage":{"bg":"SS_SHADOW_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_46"},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"어떡하지? 함선 두 대가 속수무책으로 당했잖아!","JPN":"どうする？　艦船2隻がなすすべもなくやられたんだ！","ENG":"What should we do? They took out two ships like it was nothing!","TWN":"怎麼辦？已經有兩艘艦船被毀了！"},"stage":{"bg":"SS_SHADOW_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"이 꼬마를 떨어뜨려요! 이 자들이 매달린 다음부터 움직인 거 아닙니까!","JPN":"こいつらを落としましょう！　こいつらが艦船にしがみついたせいで動き出したんじゃないですか！","ENG":"Shake off the kid! They started moving when these two grabbed on to the ship!","TWN":"把這個小傢伙甩掉！就是因為他們掛在艦船上，侵蝕體才開始動的！"},"stage":{"bg":"SS_SHADOW_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"위, 윌버 씨...... 지금 무슨 말씀을 하시는 거예요?","JPN":"ウィ、ウィルバーさん……今何を言ってるかわかってるんですか？","ENG":"M-Mister Wilbur... What are you talking about?","TWN":"韋，韋爾伯……你說什麼？"},"stage":{"bg":"SS_SHADOW_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"팔이 아파서 더는 못 버티겠어요......! 도, 도와 주세요......!","JPN":"腕が痛くてこれ以上は無理です……！　た、助けてください……！","ENG":"I can't hang on much longer! H-help!","TWN":"我的手臂好痛，快堅持不住了……！幫、幫幫我……！"},"stage":{"bg":"SS_SHADOW_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"그, 그래. 우릴 지켜 주려고 싸워 준 애를 버리는 건 너무하잖아......","JPN":"い、いや。俺らを守ろうと戦ってくれた子を見捨てるのはいくらなんでも……","ENG":"R-right... We can't just abandon the kid who fought to protect us...","TWN":"好，好。怎麼可以拋棄保護我們戰鬥的人……"},"stage":{"bg":"SS_SHADOW_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"저 괴물도 아직 공격할 것 같지는 않은데......","JPN":"あの化物もまだ攻撃してきそうにないし……","ENG":"It doesn't seem like the monsters are going to attack us just yet...","TWN":"那個怪物現在也還沒有攻擊……"},"stage":{"bg":"SS_SHADOW_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"이런 머저리들! 목숨이 달렸는데 뭘 망설여!","JPN":"間抜けども！　命がかかってんだ、何をためらう！？","ENG":"You imbeciles! Why are you hesitating?! Your lives are on the line!","TWN":"你們這些蠢貨！都自顧不暇了，還猶豫什麼！"},"stage":{"bg":"SS_SHADOW_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"총 내놔! 계속 갈겨 대면 아무리 카운터라도 계속 매달릴 수 없겠지!","JPN":"銃をよこせ！　撃ちまくればカウンターでもさすがに落ちてくれるだろ！","ENG":"Give me your gun! I doubt even a Counter can keep hanging on with bullets spraying at them!","TWN":"把槍拿來！一直打她的話，就算是制裁者也堅持不了多久的！"},"stage":{"bg":"SS_SHADOW_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MISSILE_RELOAD"},{"id":"L20_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"초, 총은 치워 주세요! 무서워요......!","JPN":"じゅ、銃はやめてください！　怖いです……！","ENG":"P-please put the gun away! You're scaring me!","TWN":"請，請把槍拿開！我好怕……！"},"stage":{"bg":"SS_SHADOW_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"하핫, 제가 당신들한테 애원할 때 뭐라고 했습니까?","JPN":"ハハッ、僕があなたたちに哀願した時はなんて言いました？","ENG":"Hah hah... Remember what you lot said when I begged to you?","TWN":"哈哈，我當初懇求你們的時候，你們是怎麼說的？"},"stage":{"bg":"SS_SHADOW_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"입장이 바뀌니 어때요? 가슴이 철렁 내려앉죠?","JPN":"立場が逆転してどう感じますか？　気分がわかりますか？","ENG":"How does it feel to be in my shoes now? Your heart just sinks, doesn't it?","TWN":"現在處境互換了，怎樣？是不是很無助？"},"stage":{"bg":"SS_SHADOW_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"하지만...... 하지만 전...... 윌버 씨를 응원하고 있었는데......!","JPN":"でも……でも私は……ウィルバーさんを応援していたのに……！","ENG":"But... But... I took your side!","TWN":"但……但是我……我一直都在支持你啊……！"},"stage":{"bg":"SS_SHADOW_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"아, 물론 그랬죠. 기억하고 있습니다.","JPN":"ああ、確かにそうでしたね。覚えています。","ENG":"Oh, of course you did. I remember.","TWN":"啊，當然了。我有記得呢。"},"stage":{"bg":"SS_SHADOW_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"당신, 그러니까 이름이......","JPN":"あなたは、確か名前が……","ENG":"And your name was...","TWN":"你，所以你叫……"},"stage":{"bg":"SS_SHADOW_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"뭐, 어쨌든.","JPN":"まぁ、とにかく。","ENG":"Oh well. Whatever.","TWN":"不管怎麼說。"},"stage":{"bg":"SS_SHADOW_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"사채업자 똘마니한테 그딴 소리를 듣다니, 살면서 처음 느껴 보는 치욕이었어요.","JPN":"闇金業者の手下に同情されるなんて、僕の人生の中で初めて味わった侮辱でした。","ENG":"Nothing was more humiliating than having to hear such things from a loan shark's errand girl.","TWN":"你不就是放高貸那些人的小跟班，卻敢對我指手畫腳，簡直是奇恥大辱。"},"stage":{"bg":"SS_SHADOW_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"네......?","JPN":"はい……？","ENG":"What?","TWN":"啊……？"},"stage":{"bg":"SS_SHADOW_05","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"당신들을 살려 주면 뭐가 남습니까? 제 빛나는 앞길을 망치려고 덤벼 들기나 하겠죠.","JPN":"あなたたちを助けてやって、僕にメリットがあると思いますか？　将来有望な僕のこの先を邪魔してくるだけでしょう。","ENG":"What do I gain from saving you two? You'll just hound me again and ruin my promising future.","TWN":"救了你們我能得到什麼？你們只會毀掉我的光輝前途。"},"stage":{"bg":"SS_SHADOW_05","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"그러니 그렇게 살고 싶으면 저한테 빌어 보세요.","JPN":"だから本当に助けてほしいなら、僕に命乞いをしてください。","ENG":"If you really want to live, why don't you beg?","TWN":"所以，如果你這麼想活著，那就求我吧。"},"stage":{"bg":"SS_SHADOW_05","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>저희가 무식해서 사람을 잘못 봤습니다.</color>","JPN":"<color=#ffd34c>私たちは無知すぎて人を見誤りました。</color>","ENG":"<color=#ffd34c>Say \\"We were too stupid to recognize your greatness.\\"</color>","TWN":"<color=#ffd34c>是我們無知，有眼不識泰山。</color>"},"stage":{"bg":"SS_SHADOW_05","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>살려 주세요, 윌버 님.</color> 이라고요.","JPN":"<color=#ffd34c>助けてくださいウィルバー様、</color>と。","ENG":"<color=#ffd34c>\\"Please save us, Dr. Wilbur.\\"</color> Say it!","TWN":"<color=#ffd34c>救救我吧，韋爾伯大人。</color>像這樣求我啊！"},"stage":{"bg":"SS_SHADOW_05","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SS_SHADOW_05","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"저, 저랑 리타 언니가...... 무, 무식해서 사람을 잘못 봤어요......","JPN":"わ、私とリタお姉ちゃんが……無知すぎて人を見誤りました……","ENG":"R-Rita and I... were too stupid to recognize your greatness...","TWN":"都怪我，我和麗塔姐姐……太、太無知，有眼不識泰山……"},"stage":{"bg":"SS_SHADOW_05","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"살려 주세요, 윌버님......!","JPN":"助けてくださいウィルバー様……！","ENG":"Please save us, Dr. Wilbur!","TWN":"救救我吧，韋爾伯大人……！"},"stage":{"bg":"SS_SHADOW_05","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"하하하하하하핫! 하란다고 진짜 하네! 이거 완전 등신 아냐?!","JPN":"あはははははっ！　本当に言うのか、バーカ！　プライドもくそもなくてみっともないな！","ENG":"Bwa hah hah hah hah! I can't believe you actually said it! You're a complete moron, aren't you?!","TWN":"哈哈哈哈哈哈哈！叫你說還真的說了呢！也太蠢了？！"},"stage":{"bg":"SS_SHADOW_05","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"싫어. 무식한 꼬맹아.","JPN":"やーだよ、クソガキ。","ENG":"Well, I don't feel like it. Stupid kid.","TWN":"才不要，你這白癡。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};